import sqlite3
from query_builder import Query

class Model:
    _table = None
    _db = None

    @classmethod
    def set_db(cls, path):
        cls._db = sqlite3.connect(path)
        cls._db.row_factory = sqlite3.Row

    @classmethod
    def find(cls, **kw):
        q = Query(cls._table)
        for k, v in kw.items():
            q.where(f"{k} = ?", v)
        sql, params = q.build()
        return [dict(r) for r in cls._db.execute(sql, params)]

    @classmethod
    def all(cls, order_by=None, limit=None, offset=None):
        q = Query(cls._table)
        if order_by:
            desc = order_by.startswith("-")
            q.order_by(order_by.lstrip("-"), desc=desc)
        if limit:
            q.limit(limit)
        if offset:
            q.offset(offset)
        sql, params = q.build()
        return [dict(r) for r in cls._db.execute(sql, params)]

class User(Model):
    _table = "users"
